from lxml import etree

def process_soap_request(soap_xml):
    try:
        # Parse the SOAP XML with DTD validation
        parser = etree.XMLParser(dtd_validation=True)
        root = etree.fromstring(soap_xml, parser=parser)

        # Find the SOAP body element
        body = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')

        if body is None:
            raise ValueError("SOAP Body not found in the XML")

        # Extract the message from the SOAP body
        message = etree.tostring(body, encoding='unicode', pretty_print=True)

        return message

    except etree.XMLSyntaxError as e:
        print(f"XML syntax error: {e}")
    except IOError as e:
        print(f"I/O error: {e}")
    except ValueError as e:
        print(f"Value error: {e}")

